export interface Layer {
  id: string;
  name: string;
  type: 'subject' | 'background' | 'lighting' | 'effect';
  prompt: string;
  isActive: boolean;
}

export interface EnhancementSuggestion {
  label: string;
  prompt: string;
  description: string;
}

export interface ImageWorkspaceState {
  id: string;
  file: File | null;
  originalPreviewUrl: string | null;
  currentPreviewUrl: string | null;
  history: string[]; // URLs of past versions
  historyIndex: number;

  status: 'idle' | 'analyzing' | 'processing' | 'error' | 'done';
  statusMessage?: string;

  analysisData?: {
    subject: string;
    type: 'portrait' | 'landscape' | 'product' | 'other';
    mood: string;
    suggestions: EnhancementSuggestion[];
  };

  layers: Layer[];
  selectedLayerId: string | null;
}

export interface VideoGenerationState {
  isGenerating: boolean;
  progress: number; // Simulated 0-100
  resultUrl: string | null;
  error: string | null;
}

import { GoogleGenAI, Type } from "@google/genai";

// Models
const ANALYSIS_MODEL = 'gemini-3-flash-preview';
const EDITING_MODEL = 'gemini-2.5-flash-image'; // "Nano Banana"
const VIDEO_MODEL = 'veo-3.1-fast-generate-preview';

// Helper to convert Blob/File to Base64
export const fileToBase64 = (file: File | Blob): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const result = reader.result as string;
      // Remove data url prefix (e.g. "data:image/jpeg;base64,")
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = error => reject(error);
  });
};

// Initialize API
const getAiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key not found in environment variables");
  }
  return new GoogleGenAI({ apiKey });
};

/**
 * Analyzes the image to detect type, subjects, and suggest enhancements.
 */
export const analyzeImage = async (file: File) => {
  const ai = getAiClient();
  const base64Data = await fileToBase64(file);

  const prompt = `
    Analyze this image efficiently. 
    1. Identify the image type (Portrait, Landscape, Product, or Other).
    2. Identify the main subject.
    3. Describe the current lighting and mood.
    4. Suggest 3 distinct professional creative enhancement styles suitable for this image (e.g., "Cyberpunk", "Minimalist Studio", "Cinematic Warmth"). 
       For each suggestion, provide a label and a short prompt description.

    Return JSON.
  `;

  const response = await ai.models.generateContent({
    model: ANALYSIS_MODEL,
    contents: {
      parts: [
        { inlineData: { mimeType: file.type, data: base64Data } },
        { text: prompt }
      ]
    },
    config: {
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          type: { type: Type.STRING, enum: ['portrait', 'landscape', 'product', 'other'] },
          subject: { type: Type.STRING },
          mood: { type: Type.STRING },
          suggestions: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                label: { type: Type.STRING },
                prompt: { type: Type.STRING },
                description: { type: Type.STRING }
              }
            }
          }
        }
      }
    }
  });

  return JSON.parse(response.text || '{}');
};

/**
 * Applies enhancements or edits to an image based on a prompt.
 * Uses the Nano Banana (gemini-2.5-flash-image) model.
 */
export const editImage = async (base64Image: string, prompt: string, mimeType: string = 'image/png') => {
  const ai = getAiClient();

  const finalPrompt = `
    Act as a professional photo editor. 
    Enhance or modify the provided image based strictly on this instruction: "${prompt}".
    Ensure the output is hyper-realistic, has cinematic lighting, and maintains high fidelity.
    Return the image only.
  `;

  const response = await ai.models.generateContent({
    model: EDITING_MODEL,
    contents: {
      parts: [
        { inlineData: { mimeType, data: base64Image } },
        { text: finalPrompt }
      ]
    },
    config: {
      // Nano Banana (2.5 flash image) does not support responseMimeType or Schema
    }
  });

  // Extract image from response
  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
    }
  }

  throw new Error("No image generated.");
};

/**
 * Generates a video from an image using Veo.
 */
export const generateVideoSequence = async (base64Image: string, prompt: string = "Cinematic slow motion camera pan, ultra realistic") => {
    // Check for API key selection for Veo models (Client-side check usually, but assuming wrapper logic here)
    if (typeof window !== 'undefined' && (window as any).aistudio) {
        const hasKey = await (window as any).aistudio.hasSelectedApiKey();
        if (!hasKey) {
             await (window as any).aistudio.openSelectKey();
             // In a real app we might wait or retry, here we assume success or fail on next call
        }
    }

    const ai = getAiClient();

    // We create a new instance to ensure fresh key if selection happened
    const aiWithKey = getAiClient();

    let operation = await aiWithKey.models.generateVideos({
      model: VIDEO_MODEL,
      prompt: prompt,
      image: {
        imageBytes: base64Image,
        mimeType: 'image/png' // Assuming PNG for simplicity in this demo context
      },
      config: {
        numberOfVideos: 1,
        resolution: '720p',
        aspectRatio: '16:9'
      }
    });

    // Polling
    while (!operation.done) {
      await new Promise(resolve => setTimeout(resolve, 5000));
      operation = await aiWithKey.operations.getVideosOperation({ operation });
    }

    const videoUri = operation.response?.generatedVideos?.[0]?.video?.uri;
    if (!videoUri) throw new Error("Video generation failed");

    // Fetch the actual video bytes using the API key
    const videoRes = await fetch(`${videoUri}&key=${process.env.API_KEY}`);
    const blob = await videoRes.blob();
    return URL.createObjectURL(blob);
};

import React, { useState } from 'react';
import { VideoGenerationState } from '../types';
import { generateVideoSequence, fileToBase64 } from '../services/geminiService';

interface Props {
  selectedImage: string | null; // Base64 or URL
  onClose: () => void;
}

const VideoGenerator: React.FC<Props> = ({ selectedImage, onClose }) => {
  const [state, setState] = useState<VideoGenerationState>({
    isGenerating: false,
    progress: 0,
    resultUrl: null,
    error: null
  });
  const [prompt, setPrompt] = useState("Cinematic slow pan, atmospheric lighting, 4k detail");

  const handleGenerate = async () => {
    if (!selectedImage) return;

    setState(prev => ({ ...prev, isGenerating: true, error: null, progress: 10 }));

    try {
      // If selectedImage is a blob URL, we need to fetch it to get base64
      let base64Data = selectedImage;
      if (selectedImage.startsWith('blob:') || selectedImage.startsWith('http')) {
        const res = await fetch(selectedImage);
        const blob = await res.blob();
        base64Data = await fileToBase64(blob);
      } else if (selectedImage.startsWith('data:')) {
        base64Data = selectedImage.split(',')[1];
      }

      setState(prev => ({ ...prev, progress: 30 }));

      const videoUrl = await generateVideoSequence(base64Data, prompt);

      setState(prev => ({ ...prev, isGenerating: false, progress: 100, resultUrl: videoUrl }));
    } catch (e: any) {
      setState(prev => ({ ...prev, isGenerating: false, error: e.message || "Failed to generate video" }));
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
      <div className="glass-panel w-full max-w-2xl rounded-2xl p-6 relative flex flex-col gap-6 overflow-hidden">

        {/* Header */}
        <div className="flex justify-between items-center border-b border-white/10 pb-4">
          <h2 className="text-2xl font-bold bg-gradient-to-r from-cyan-400 to-purple-500 bg-clip-text text-transparent">
            Veo Video Sequence
          </h2>
          <button onClick={onClose} className="text-slate-400 hover:text-white transition-colors">
            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
          </button>
        </div>

        <div className="flex flex-col md:flex-row gap-6">
          {/* Source Preview */}
          <div className="w-full md:w-1/3 aspect-video bg-slate-800 rounded-lg overflow-hidden border border-slate-700 relative group">
             {selectedImage ? (
               <img src={selectedImage} alt="Source" className="w-full h-full object-cover" />
             ) : (
               <div className="flex items-center justify-center h-full text-xs text-slate-500">No Source</div>
             )}
             <div className="absolute top-2 left-2 bg-black/60 px-2 py-1 rounded text-xs text-white">Source</div>
          </div>

          {/* Controls */}
          <div className="flex-1 space-y-4">
            <div>
              <label className="block text-xs font-medium text-cyan-400 mb-1 uppercase tracking-wider">Motion Prompt</label>
              <textarea 
                value={prompt}
                onChange={(e) => setPrompt(e.target.value)}
                className="w-full bg-slate-900/50 border border-slate-700 rounded-lg p-3 text-sm text-slate-200 focus:border-cyan-500 focus:outline-none focus:ring-1 focus:ring-cyan-500 resize-none h-24"
                placeholder="Describe camera movement and scene action..."
              />
            </div>

            {state.error && (
              <div className="p-3 bg-red-500/10 border border-red-500/30 rounded text-red-400 text-sm">
                {state.error}
              </div>
            )}

            <button
              onClick={handleGenerate}
              disabled={state.isGenerating || !selectedImage}
              className={`w-full py-3 rounded-lg font-semibold tracking-wide transition-all duration-300 ${
                state.isGenerating 
                  ? 'bg-slate-800 text-slate-500 cursor-not-allowed' 
                  : 'bg-gradient-to-r from-cyan-600 to-purple-600 hover:from-cyan-500 hover:to-purple-500 text-white shadow-lg hover:shadow-cyan-500/25'
              }`}
            >
              {state.isGenerating ? 'Generating Sequence...' : 'Generate Video'}
            </button>
          </div>
        </div>

        {/* Result Area */}
        {state.resultUrl && (
          <div className="mt-2 space-y-2 animate-in fade-in slide-in-from-bottom-4 duration-500">
             <div className="flex items-center gap-2 text-green-400 text-sm font-medium">
                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polyline points="20 6 9 17 4 12"></polyline></svg>
                Generation Complete
             </div>
             <div className="w-full aspect-video bg-black rounded-lg overflow-hidden border border-slate-700">
                <video src={state.resultUrl} controls className="w-full h-full object-contain" autoPlay loop />
             </div>
             <a href={state.resultUrl} download="sequence.mp4" className="block text-center text-xs text-cyan-400 hover:underline">Download Video</a>
          </div>
        )}

        {state.isGenerating && (
          <div className="absolute bottom-0 left-0 h-1 bg-gradient-to-r from-cyan-500 via-purple-500 to-cyan-500 animate-pulse w-full"></div>
        )}
      </div>
    </div>
  );
};

